def list_all_users(client):
    """Collect every user in the org via cursor pagination."""
    users = []
    after = None

    while True:
        params = {"limit": 100}
        if after:
            params["after"] = after

        page = client.admin.users.list(**params)
        users.extend(page.data)

        if not page.has_more:
            break
        after = page.last_id

    return users

all_users = list_all_users(client)
print(f"{len(all_users)} members in the org")

import anthropic, time

def invite_with_retry(client, email: str, role: str, max_retries: int = 3):
    for attempt in range(max_retries):
        try:
            return client.admin.invites.create(email=email, role=role)
        except anthropic.RateLimitError:
            wait = 2 ** attempt         # 1s, 2s, 4s
            print(f"Rate limited, retrying in {wait}s...")
            time.sleep(wait)
        except anthropic.ConflictError:
            print(f"{email} already a member or has a pending invite")
            return None
        except anthropic.PermissionDeniedError as e:
            raise RuntimeError(f"Admin key lacks invite permission: {e}") from e
    raise RuntimeError(f"Failed to invite {email} after {max_retries} attempts")

import time, anthropic

def bulk_invite(client, emails: list[str], role: str = "developer",
                delay_ms: int = 200):
    """Invite a batch of users while respecting rate limits."""
    results = []
    for email in emails:
        for backoff in [1, 2, 4]:
            try:
                inv = client.admin.invites.create(email=email, role=role)
                results.append({"email": email, "status": "invited", "id": inv.id})
                break
            except anthropic.RateLimitError:
                time.sleep(backoff)
        else:
            results.append({"email": email, "status": "failed"})
        time.sleep(delay_ms / 1000)   # polite inter-request gap
    return results
